number_column_right_npc.script:
					local nOriginalAT;
					
					function onInit()
						super.onInit();
						ValidateValue();
						nOriginalAT = getValue();
						CheckProtection();
					end

					function onValueChanged()
						ValidateValue();
						CheckProtection();
						nOriginalAT = getValue();
					end

					function ValidateValue()
						local nAT = getValue();
						if nAT < 1 then
							setValue(1);
						elseif nAT > 20 then
							setValue(20);
						end
					end

					function CheckProtection()
						local nAT = getValue();
						if nOriginalAT ~= nAT then 
							local vArmor = Rules_ArmorTypes.GetATDetails(nAT);
							if vArmor and vArmor.protectionHead then
								window.protection_head.setValue(vArmor.protectionHead);
							else
								window.protection_head.setValue("");
							end
							if vArmor and vArmor.protectionFace then
								window.protection_face.setValue(vArmor.protectionFace);
							else
								window.protection_face.setValue("");
							end
							if vArmor and vArmor.protectionNeck then
								window.protection_neck.setValue(vArmor.protectionNeck);
							else
								window.protection_neck.setValue("");
							end
							if vArmor and vArmor.protectionTorso then
								window.protection_torso.setValue(vArmor.protectionTorso);
							else
								window.protection_torso.setValue("");
							end
							if vArmor and vArmor.protectionArms then
								window.protection_arms.setValue(vArmor.protectionArms);
							else
								window.protection_arms.setValue("");
							end
							if vArmor and vArmor.protectionLegs then
								window.protection_legs.setValue(vArmor.protectionLegs);
							else
								window.protection_legs.setValue("");
							end
						end
					end

dice_ghost.script:
					function action(draginfo)
						local charNode = window.getDatabaseNode();
						local rActor = ActorManager.resolveActor(charNode);
						local sSkillName = ActionSkill.MovementMM;
						local nSkillMod = 0;
						local nSkillType = ActionSkill.MM;
						ActionSkill.performRoll(draginfo, rActor, sSkillName, nSkillMod, nSkillType);
						return true;
					end

					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end

					function onDoubleClick(x,y)
						return action();
					end

function action(draginfo)
