windowlist.script:
					function onInit()
						if super and super.onInit then
							super.onInit();
						end
						--[[ load the stat list ]]
						local statList = Rules_Stats.List();
						for i = 1, #statList do
							addEntry(statList[i].name, statList[i].label, statList[i].displayname, statList[i].devStat, statList[i].order);
						end
						--[[ force a re-sort ]]
						applySort();
					end

					function addEntry(name, label, displayname, dev, order)
						local node = DB.getChild(getDatabaseNode(), name);
						local win;
						if not node then
							node = DB.createChild(getDatabaseNode(), name);
						end
						for i,w in ipairs(getWindows()) do
							if DB.getName(w.getDatabaseNode())==name then
								win = w;
							end
						end
						if win then
							win.label.setValue(label);
							win.label.setTooltipText("Drag or double click to roll a " .. displayname .. " stat check");
							win.abbr.setValue(label);
							win.name.setValue(displayname);
							win.order.setValue(order);
						end
					end

					function onSortCompare(w1, w2)
						return (w1.order.getValue() > w2.order.getValue());
					end

					function update(bReadOnly, bForceHide)
						local bLocalShow;
						if bForceHide then
							bLocalShow = false;
						else
							bLocalShow = true;
							if bReadOnly and not nohide and isEmpty() then
								bLocalShow = false;
							end
						end
						
						setVisible(bLocalShow);
						setReadOnly(bReadOnly);

						local sListName = getName();
						if window[sListName .. "_header"] then
							window[sListName .. "_header"].setVisible(bLocalShow);
						end
						
						local bEditMode = false;
						if window[sListName .. "_iedit"] then
							if bReadOnly then
								window[sListName .. "_iedit"].setValue(0);
								window[sListName .. "_iedit"].setVisible(false);
							else
								window[sListName .. "_iedit"].setVisible(true);
								bEditMode = (window[sListName .. "_iedit"].getValue() ~= 0);
							end
						end

						for _,w in ipairs(getWindows()) do
							if w.update then
								w.update(bReadOnly);
							elseif w.name then
								w.name.setReadOnly(bReadOnly);
							end
						end
						
						return bLocalShow;
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end

						local rrList = Rules_RR.List_Base();
						for i = 1, #rrList do
							addEntry(rrList[i].order, rrList[i].resistancetype, rrList[i].label, rrList[i].stat);
						end

						applySort();
					end

					function addEntry(order, resistancetype, label, stat)
						local name = string.lower(label);
						name = string.gsub(name, "/", "_");
						local node = DB.getChild(getDatabaseNode(), name);
						local win;
						if not node then
							node = DB.createChild(getDatabaseNode(), name);
						end
						for i,w in ipairs(getWindows()) do
							if DB.getName(w.getDatabaseNode())==name then
								win = w;
							end
						end
						if win then
							win.label.setValue(label);
							win.label.setTooltipText("Drag or double click to roll a " .. label .. " RR");
							win.name.setValue(label);
							win.order.setValue(order);
							win.statname.setValue(stat);
						end
					end

					function onSortCompare(w1, w2)
						return (w1.order.getValue() > w2.order.getValue());
					end

					function update(bReadOnly, bForceHide)
						local bLocalShow;
						if bForceHide then
							bLocalShow = false;
						else
							bLocalShow = true;
							if bReadOnly and not nohide and isEmpty() then
								bLocalShow = false;
							end
						end
						
						setVisible(bLocalShow);
						setReadOnly(bReadOnly);

						local sListName = getName();
						if window[sListName .. "_header"] then
							window[sListName .. "_header"].setVisible(bLocalShow);
						end
						
						local bEditMode = false;
						if window[sListName .. "_iedit"] then
							if bReadOnly then
								window[sListName .. "_iedit"].setValue(0);
								window[sListName .. "_iedit"].setVisible(false);
							else
								window[sListName .. "_iedit"].setVisible(true);
								bEditMode = (window[sListName .. "_iedit"].getValue() ~= 0);
							end
						end

						for _,w in ipairs(getWindows()) do
							if w.update then
								w.update(bReadOnly);
							elseif w.name then
								w.name.setReadOnly(bReadOnly);
							end
						end
						
						return bLocalShow;
					end

					function onInit()
						if super and super.onInit then
							super.onInit();
						end

						local rrList = Rules_RR.List_Hybrid();
						for i = 1, #rrList do
							addEntry(rrList[i].order, rrList[i].resistancetype, rrList[i].label, rrList[i].resistances);
						end

						applySort();
					end

					function addEntry(order, resistancetype, label, resistances)
						local name = string.lower(label);
						name = string.gsub(name, "/", "_");
						local node = DB.getChild(getDatabaseNode(), name);
						local win;
						if not node then
							node = DB.createChild(getDatabaseNode(), name);
						end
						for i,w in ipairs(getWindows()) do
							if DB.getName(w.getDatabaseNode())==name then
								win = w;
							end
						end
						if win then
							win.label.setValue(label);
							win.label.setTooltipText("Drag or double click to roll a " .. label .. " RR");
							win.name.setValue(label);
							win.order.setValue(order);
							win.resistances.setValue(resistances);
						end
					end

					function onSortCompare(w1, w2)
						return (w1.order.getValue() > w2.order.getValue());
					end
					
					function update(bReadOnly, bForceHide)
						local bLocalShow;
						if bForceHide then
							bLocalShow = false;
						else
							bLocalShow = true;
							if bReadOnly and not nohide and isEmpty() then
								bLocalShow = false;
							end
						end
						
						setVisible(bLocalShow);
						setReadOnly(bReadOnly);

						local sListName = getName();
						if window[sListName .. "_header"] then
							window[sListName .. "_header"].setVisible(bLocalShow);
						end
						
						local bEditMode = false;
						if window[sListName .. "_iedit"] then
							if bReadOnly then
								window[sListName .. "_iedit"].setValue(0);
								window[sListName .. "_iedit"].setVisible(false);
							else
								window[sListName .. "_iedit"].setVisible(true);
								bEditMode = (window[sListName .. "_iedit"].getValue() ~= 0);
							end
						end

						for _,w in ipairs(getWindows()) do
							if w.update then
								w.update(bReadOnly);
							elseif w.name then
								w.name.setReadOnly(bReadOnly);
							end
						end
						
						return bLocalShow;
					end

