list_column.script:
					function addItem(source)
						local newentry = createWindow();

						--[[ Descriptive fields ]]
						newentry.name.setValue(DB.getValue(source, "name", ""));

						--[[ Custom? ]]
						if DB.getValue(source, "custom", 0) == 1 then
							newentry.custom.setValue(1);
						else
							newentry.custom.setValue(0);
						end

						--[[ Shortcut ]]
						newentry.open.setValue("spelllist", DB.getPath(source));
						newentry.open.setVisible(true);

						--[[ re-initialise 
						newentry.onInit(); ]]

						return newentry;
					end

					function onDrop(x, y, draginfo)
						if draginfo.isType("spelllist") then
							local win = draginfo.getCustomData();
							local source = win.getDatabaseNode();
							addItem(source);
							return true;
						elseif draginfo.isType("shortcut") then
							local class = draginfo.getShortcutData();
							local source = draginfo.getDatabaseNode();
							if source and class == "spelllist" then
								addItem(source);
								return true;
							end
						end
						return false;
					end

					function update(bReadOnly, bForceHide)
						local bLocalShow = super.update(bReadOnly, bForceHide);
						
						for _,w in ipairs(getWindows()) do
							w.name.setReadOnly(bReadOnly);
							w.esf.setReadOnly(bReadOnly);
							w.maxlevel.setReadOnly(bReadOnly);
						end
						
						return bLocalShow;
					end

