npc_strfield.script:
function Climate()
	local codes = getValue();
	local code, t = "", "";
	local txt = "";
	local txts = {h="Hot/Humid", n="Hot/Average", a="Hot/Dry", w="Warm/Humid", m="Warm/Average", 
			s="Warm/Dry", k="Cool/Average", t="Cool/Dry", c="Cool/Dry", f="Frigid"};
	for i=1,string.len(codes),1 do
		code = string.sub(codes,i,i);
		if txts[code] ~= nil then
			if txt=="" then txt = txts[code]; else txt = txt..", "..txts[code]; end
		end
	end
	window.climate_txt.setValue(txt);
end
function onValueChanged()
	Climate();
end
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	onValueChanged();
end

function SetFromCode()
	local vp="Very Poor";
	local p="Poor";
	local n="Normal";
	local r="Rich";
	local vr="Very Rich";
	local sp="Special";
	local magic = {a=vp,b=vp,c=vp,d=vp,e=vp,e=vp,f=p,g=p,h=p,i=p,j=p,
					k=n,l=n,m=n,n=n,o=n,p=r,q=r,r=r,s=r,t=r,u=vr,v=vr,w=vr,x=vr,y=vr,z=sp};
	local money = {a=vp,b=p,c=n,d=r,e=vr,f=vp,g=p,h=n,i=r,j=vr,
					k=vp,l=p,m=n,n=r,o=vr,p=vp,q=p,r=n,s=r,t=vr,u=vp,v=p,w=n,x=r,y=vr,z=sp};
	window.treasure_magic.setValue(magic[getValue()]);
	window.treasure_money.setValue(money[getValue()]);
end
function onValueChanged()
	SetFromCode();
end

