npc_numfield_underlined.script:
					function onInit()
						local node = window.getDatabaseNode();
						DB.addHandler(DB.getPath(node, "bonus"), "onUpdate", self.refresh);
						DB.addHandler(DB.getPath(node, "race"), "onUpdate", self.refresh);
						DB.addHandler(DB.getPath(node, "misc"), "onUpdate", self.refresh);
						self.refresh();
					end

					function refresh()
						setValue(window.bonus.getValue() + window.race.getValue() + window.misc.getValue());
					end

					function onDragStart(button, x, y, draginfo)
						draginfo.setType("number");
						draginfo.setDescription(window.name.getValue().." Bonus");
						if getValue() >= 0 then
							draginfo.setStringData(window.name.getValue().." Bonus +"..getValue());
						else
							draginfo.setStringData(window.name.getValue().." Bonus "..getValue());
						end
						draginfo.setNumberData(getValue());
						return true;
					end

function onInit()
	OptionsManager.registerCallback("RC44B", refresh);
	OptionsManager.registerCallback("RC48B", refresh);
	refresh();
end
function onClose()
	OptionsManager.unregisterCallback("RC44B", refresh);
	OptionsManager.unregisterCallback("RC48B", refresh);
end
function onValueChanged()
	refresh();
end
function refresh()
	if getValue() == 0 then
		window.bonus.setValue(0);
	else
		window.bonus.setValue(Rules_Stats.Bonus(getValue()));
	end
end

