hs.script:
					function onInit()
						local nodeNPC = DB.getChild(getDatabaseNode(), ".....");

						DB.addHandler(DB.getPath(nodeNPC, "rr.base.essence.total"),"onUpdate", refresh);
						DB.addHandler(DB.getPath(nodeNPC, "rr.base.channeling.total"),"onUpdate", refresh);
						DB.addHandler(DB.getPath(nodeNPC, "rr.base.mentalism.total"),"onUpdate", refresh);

						refresh();
					end
					
					function refresh()
						local nodeNPC = DB.getChild(getDatabaseNode(), ".....");
						local nAverage = 0;
						local nCount = 0;
						
						if string.len(getValue()) > 0 then
							if string.find(getValue(), "Essence") then
								nAverage = nAverage + DB.getValue(nodeNPC, "rr.base.essence.total", 0);
								nCount = nCount + 1;
							end
							if string.find(getValue(), "Channeling") then
								nAverage = nAverage + DB.getValue(nodeNPC, "rr.base.channeling.total", 0);
								nCount = nCount + 1;
							end
							if string.find(getValue(), "Mentalism") then
								nAverage = nAverage + DB.getValue(nodeNPC, "rr.base.mentalism.total", 0);
								nCount = nCount + 1;
							end
							if nCount > 0 then
								nAverage = math.floor((nAverage / nCount) + 0.5);
							end
						end
						window.base.setValue(nAverage);
					end

