windowclass.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	local node = getDatabaseNode();    
	if not open.getValue() then
		open.setValue("skill", DB.getPath(node));
	end
	open.setVisible(true);
end

string_listitem_center_underline.script:
					function action(draginfo)
						local nodeSkill = DB.getParent(getDatabaseNode());
						local charNode = DB.getChild(getDatabaseNode(), "....");
						local rActor = ActorManager.resolveActor(charNode);
						sSkillName = getValue();

						nSkillMod = DB.getValue(nodeSkill, "bonus", 0);

						local class, refNodeName = window.open.getValue();
						if refNodeName and refNodeName ~= "" then
							refSkillNode = DB.findNode(refNodeName);
							if refSkillNode then			
								skillType = DB.getValue(refSkillNode, "type", "");
							end
						end

						if skillType == ActionSkill.MM then
							nSkillType = ActionSkill.MM;
						else
							nSkillType = ActionSkill.SM;
						end

						ActionSkill.performRoll(draginfo, rActor, sSkillName, nSkillMod, nSkillType);
						return true;
					end
					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end
					function onDoubleClick(x,y)
						return action();
					end

windowclass.script:
function onInit()
	if super and super.onInit then
		super.onInit();
	end
	local node = getDatabaseNode();
	if DB.getValue(node, "custom", 0) ~= 0 then
		custom.setValue(1);
	else
		custom.setValue(0);
	end
	if not open.getValue() then
		open.setValue("spelllist", DB.getPath(node));
	end
	open.setVisible(true); 
end

hn.script:
function onValueChanged()
	if getValue() == 1 then
		window.name.setReadOnly(false);
		window.name.setFrame("textline",0,1,0,0);
	else
		window.name.setReadOnly(true);
		window.name.setFrame(nil);
	end
end

string_listitem_center_underline.script:
                    function action(draginfo)
                        local charNode = DB.getChild(window.getDatabaseNode(), "...");
                        local rActor = ActorManager.resolveActor(charNode);
                        local sClass, sRecordName = window.open.getValue();
                        local sRealm = window.windowlist.window.realm.getValue();
                        local nESFTotal = 0;
                        local esf_value = DB.getValue(window.getDatabaseNode(), "esf", "0");
                        if esf_value then
                            nESFTotal = tonumber(esf_value) or 0;
                        end
                        
                        local nSpellLevel = DB.getValue(window.getDatabaseNode(), "level", 0);

                        if nESFTotal < 0 then
                            nESFTotal = 0;
                        end
                        ActionBaseCasting.performRoll(draginfo, rActor, getValue(), sRecordName, sRealm, Rules_Spells.GetSpellFailure(nESFTotal), { sSpellName = getValue(), sSpellNodeName = sRecordName, nSpellLevel = nSpellLevel });
                        return true;
                    end

					function onDragStart(button, x, y, draginfo)
						return action(draginfo);
					end

					function onDoubleClick(x,y)
						return action();
					end
